/**
 * Pure phone number validation and normalization functions.
 *
 * No side effects — can be reused across services and adapters.
 * Accepts E.164 format phone numbers (e.g., +14155551234).
 */

/**
 * Validate that a string is a valid E.164 phone number.
 * E.164: + followed by 1-15 digits, no spaces or dashes.
 */
export function isValidPhoneNumber(phone: string): boolean {
  return /^\+[1-9]\d{1,14}$/.test(phone);
}

/**
 * Normalize a phone number: trim whitespace and strip spaces/dashes.
 */
export function normalizePhoneNumber(phone: string): string {
  return phone.trim().replace(/[\s\-()]/g, '');
}

/**
 * SMS notification adapter — delivers notifications via SMS.
 *
 * Implements NotificationAdapter interface per the event-driven notification
 * architecture. Registered with NotificationService at startup.
 *
 * Features:
 * - Message formatting: truncates body to SMS-friendly length with subject prefix
 * - Phone number validation: validates E.164 format before sending
 * - Configurable transport: supports pluggable send function for testing/production
 * - Error handling: never throws, returns failed NotificationResult on errors
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';
import { isValidPhoneNumber, normalizePhoneNumber } from '../validators/phone.validator.js';

/**
 * Maximum length of an SMS message body.
 * Standard SMS limit is 160 characters for a single segment.
 */
const MAX_SMS_LENGTH = 160;

/**
 * Represents a sent SMS message for inspection/testing.
 */
export interface SmsMessage {
  to: string;
  body: string;
  sentAt: Date;
}

/**
 * Configuration for the SmsAdapter.
 */
export interface SmsAdapterConfig {
  /** Custom send function — defaults to in-memory logging */
  sendFn?: (to: string, body: string) => Promise<void>;
}

const DEFAULT_CONFIG: SmsAdapterConfig = {};

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private sentMessages: SmsMessage[] = [];
  private config: SmsAdapterConfig;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Validate and normalize the recipient phone number.
   * Returns the normalized phone number or null if invalid.
   */
  resolveRecipient(recipient: string): string | null {
    const normalized = normalizePhoneNumber(recipient);
    if (!isValidPhoneNumber(normalized)) {
      this.logger.warn(`Invalid phone number: ${recipient}`);
      return null;
    }
    return normalized;
  }

  /**
   * Format a notification payload into an SMS-friendly text message.
   * Truncates to MAX_SMS_LENGTH characters.
   */
  formatMessage(payload: NotificationPayload): string {
    const full = `${payload.subject}: ${payload.body}`;
    if (full.length <= MAX_SMS_LENGTH) {
      return full;
    }
    return full.substring(0, MAX_SMS_LENGTH - 3) + '...';
  }

  /**
   * Send a notification through the SMS channel.
   * Never throws — returns a failed NotificationResult on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      // Validate recipient
      const resolvedRecipient = this.resolveRecipient(payload.recipient);
      if (!resolvedRecipient) {
        return {
          success: false,
          notificationId: payload.id,
          channel: 'sms',
          error: `Invalid phone number: ${payload.recipient}`,
          deliveredAt: new Date(),
        };
      }

      // Format message
      const body = this.formatMessage(payload);

      // Send via transport
      if (this.config.sendFn) {
        await this.config.sendFn(resolvedRecipient, body);
      }

      const message: SmsMessage = {
        to: resolvedRecipient,
        body,
        sentAt: new Date(),
      };

      this.sentMessages.push(message);
      this.logger.info(`SMS sent to ${resolvedRecipient}: ${payload.subject}`);

      return {
        success: true,
        notificationId: payload.id,
        channel: 'sms',
        deliveredAt: message.sentAt,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${errorMessage}`);
      return {
        success: false,
        notificationId: payload.id,
        channel: 'sms',
        error: errorMessage,
        deliveredAt: new Date(),
      };
    }
  }

  /**
   * Get all sent SMS messages. Useful for testing.
   */
  getSentMessages(): SmsMessage[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent messages. Useful for testing.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    id: 'notif-0001',
    type: 'order-confirmation',
    channel: 'sms',
    recipient: '+14155551234',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    priority: 'normal',
    createdAt: new Date('2026-01-01T00:00:00Z'),
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('send', () => {
    it('should send an SMS successfully', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('sms');
      expect(result.deliveredAt).toBeInstanceOf(Date);
    });

    it('should store sent messages for inspection', async () => {
      await adapter.send(makePayload());

      const messages = adapter.getSentMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]?.to).toBe('+14155551234');
    });

    it('should accumulate multiple sent messages', async () => {
      await adapter.send(makePayload({ id: 'notif-0001' }));
      await adapter.send(makePayload({ id: 'notif-0002', recipient: '+14155559999' }));

      expect(adapter.getSentMessages()).toHaveLength(2);
    });

    it('should clear sent messages', async () => {
      await adapter.send(makePayload());
      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('recipient validation', () => {
    it('should accept valid E.164 phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: '+14155551234' }));
      expect(result.success).toBe(true);
    });

    it('should normalize phone numbers by stripping spaces', async () => {
      await adapter.send(makePayload({ recipient: '+1 415 555 1234' }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+14155551234');
    });

    it('should normalize phone numbers by stripping dashes', async () => {
      await adapter.send(makePayload({ recipient: '+1-415-555-1234' }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+14155551234');
    });

    it('should normalize phone numbers by stripping parentheses', async () => {
      await adapter.send(makePayload({ recipient: '+1(415)5551234' }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.to).toBe('+14155551234');
    });

    it('should reject invalid phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-a-phone' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should reject empty phone numbers', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should reject phone numbers without + prefix', async () => {
      const result = await adapter.send(makePayload({ recipient: '14155551234' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid phone number');
    });

    it('should resolve valid recipient via resolveRecipient', () => {
      expect(adapter.resolveRecipient('+14155551234')).toBe('+14155551234');
    });

    it('should resolve and normalize via resolveRecipient', () => {
      expect(adapter.resolveRecipient('+1 415 555 1234')).toBe('+14155551234');
    });

    it('should return null for invalid recipient via resolveRecipient', () => {
      expect(adapter.resolveRecipient('invalid')).toBeNull();
    });
  });

  describe('message formatting', () => {
    it('should combine subject and body', async () => {
      await adapter.send(makePayload({
        subject: 'Test Subject',
        body: 'Test body content',
      }));

      const messages = adapter.getSentMessages();
      expect(messages[0]?.body).toBe('Test Subject: Test body content');
    });

    it('should truncate long messages to 160 characters', () => {
      const longBody = 'A'.repeat(200);
      const payload = makePayload({ subject: 'Subject', body: longBody });
      const formatted = adapter.formatMessage(payload);

      expect(formatted.length).toBe(160);
      expect(formatted.endsWith('...')).toBe(true);
    });

    it('should not truncate messages at exactly 160 characters', () => {
      const payload = makePayload({
        subject: 'S',
        body: 'B'.repeat(156), // "S: " + 156 = 159 chars
      });
      const formatted = adapter.formatMessage(payload);

      expect(formatted.length).toBeLessThanOrEqual(160);
      expect(formatted.endsWith('...')).toBe(false);
    });

    it('should format all notification types', async () => {
      for (const type of ['order-confirmation', 'order-status-update', 'user-welcome', 'user-profile-update'] as const) {
        adapter.clearSentMessages();
        await adapter.send(makePayload({ type, subject: `${type} subject`, body: `${type} body` }));
        const messages = adapter.getSentMessages();
        expect(messages[0]?.body).toContain(type);
      }
    });
  });

  describe('custom transport', () => {
    it('should call custom sendFn when provided', async () => {
      const sent: Array<{ to: string; body: string }> = [];
      const customAdapter = new SmsAdapter({
        sendFn: async (to, body) => { sent.push({ to, body }); },
      });

      await customAdapter.send(makePayload());

      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+14155551234');
    });

    it('should return failure when sendFn throws', async () => {
      const customAdapter = new SmsAdapter({
        sendFn: async () => { throw new Error('SMS gateway unavailable'); },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('SMS gateway unavailable');
      expect(customAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should still store message when using default transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);
    });
  });

  describe('channel property', () => {
    it('should report sms as its channel', () => {
      expect(adapter.channel).toBe('sms');
    });
  });
});

